    pub reversible: bool,
}

/// Warning level for confirmation prompts.
#[derive(Clone, Copy, Debug, PartialEq, Eq, serde::Serialize, serde::Deserialize)]
pub enum ConfirmationLevel {
    /// Informational (no danger)
    Info,
