            self.data_manager.alert_manager.acknowledge(alert_id);
            self.status_message = Some(format!("Acknowledged alert for {}", worker_id));
            self.mark_dirty();
        } else {
            self.status_message = Some("No alert selected".to_string());
            self.mark_dirty();
        }
    }

