    // ========== Model Routing & Complexity Scoring ==========

    /// Score a task's complexity (0-100).
    ///
    /// Uses the ComplexityScorer to analyze task title, description, labels,
    /// and other factors to determine the appropriate model tier.
    pub fn score_task_complexity(
        &self,
        title: &str,
        description: Option<&str>,
        labels: &[String],
    ) -> u32 {
        let mut context = TaskContext::new(title)
            .with_labels(labels.to_vec());

        if let Some(desc) = description {
            context = context.with_description(desc);
        }

        self.complexity_scorer.score(&context).score
    }

    /// Route a task to the appropriate model tier.
    ///
    /// Uses the Router to make intelligent routing decisions based on
    /// task priority, complexity, and subscription availability.
    pub fn route_task(
        &mut self,
        bead_id: &str,
        title: &str,
        priority: Priority,
        labels: Vec<String>,
    ) -> Option<forge_worker::router::RoutingDecision> {
        // Score complexity
        let complexity_score = self.score_task_complexity(title, None, &labels);

        // Create task metadata
        let task = TaskMetadata::new(bead_id, priority)
            .with_complexity(complexity_score)
            .with_labels(labels);

        // Make routing decision
        match self.router.route(&task) {
            Ok(decision) => {
                // Update routing data for display
                self.routing_data.total_decisions += 1;
                *self.routing_data.by_tier.entry(decision.tier).or_insert(0) += 1;
                *self.routing_data.by_model.entry(decision.model_id.clone()).or_insert(0) += 1;
                *self.routing_data.by_reason.entry(decision.reason).or_insert(0) += 1;

                // Track recent decisions (keep last 20)
                self.routing_data.recent_decisions.push(decision.clone());
                if self.routing_data.recent_decisions.len() > 20 {
                    self.routing_data.recent_decisions.remove(0);
                }

                // Update complexity distribution
                match decision.tier {
                    forge_core::types::WorkerTier::Budget => {
                        self.routing_data.complexity_distribution.0 += 1;
                    }
                    forge_core::types::WorkerTier::Standard => {
                        self.routing_data.complexity_distribution.1 += 1;
                    }
                    forge_core::types::WorkerTier::Premium => {
                        self.routing_data.complexity_distribution.2 += 1;
                    }
                }

                // Calculate average complexity
                let total = self.routing_data.total_decisions;
                self.routing_data.avg_complexity =
                    (self.routing_data.avg_complexity * (total - 1) as f64 + complexity_score as f64)
                    / total as f64;

                // Calculate savings
                self.routing_data.calculate_savings();
                self.routing_data.last_update = Some(std::time::Instant::now());
                self.routing_data.is_loading = false;

                Some(decision)
            }
            Err(e) => {
                tracing::warn!("Routing decision failed for {}: {}", bead_id, e);
                None
            }
        }
    }

    /// Get the current router statistics.
    pub fn router_stats(&self) -> forge_worker::router::RouterStats {
        self.router.stats()
    }

    /// Get the recommended model tier for a task.
    pub fn get_recommended_tier(&self, title: &str, labels: &[String]) -> forge_core::types::WorkerTier {
        let complexity = self.score_task_complexity(title, None, labels);
        match complexity {
            0..=30 => forge_core::types::WorkerTier::Budget,
            31..=60 => forge_core::types::WorkerTier::Standard,
            _ => forge_core::types::WorkerTier::Premium,
        }
    }

    /// Poll routing data for display updates.
    ///
    /// This should be called periodically to update routing stats
    /// from the router's internal state.
    pub fn poll_routing_data(&mut self) {
        let should_poll = self.last_routing_poll.map_or(true, |t| {
            t.elapsed().as_secs() >= 5 // Poll every 5 seconds
        });

        if !should_poll {
            return;
        }

        // Sync router stats with routing data
        let stats = self.router.stats();
        self.routing_data.total_decisions = stats.total_decisions;
        self.routing_data.by_tier = stats.by_tier.clone();
        self.routing_data.by_model = stats.by_model.clone();
        self.routing_data.by_reason = stats.by_reason.clone();

        // Keep recent decisions from router history
        let history = self.router.history();
        self.routing_data.recent_decisions = history.iter().rev().take(20).cloned().collect();

        // Calculate savings
        self.routing_data.calculate_savings();
        self.routing_data.last_update = Some(std::time::Instant::now());
        self.routing_data.is_loading = false;

        self.last_routing_poll = Some(std::time::Instant::now());
    }
}

impl Default for DataManager {
    fn default() -> Self {
        Self::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_format_model_name() {
        assert_eq!(format_model_name("claude-code-glm-47"), "GLM-4.7");
        assert_eq!(format_model_name("glm47"), "GLM-4.7");
        assert_eq!(format_model_name("sonnet-4.5"), "Sonnet");
        assert_eq!(format_model_name("claude-opus-4.6"), "Opus");
        assert_eq!(format_model_name("haiku"), "Haiku");
        assert_eq!(format_model_name(""), "Unknown");
        assert_eq!(format_model_name("custom-model"), "custom-model");
    }

    #[test]
    fn test_truncate_string() {
        assert_eq!(truncate_string("hello", 10), "hello");
        assert_eq!(truncate_string("hello world", 5), "hell…");
        assert_eq!(truncate_string("ab", 2), "ab");
        assert_eq!(truncate_string("abc", 2), "ab");
    }

    #[test]
    fn test_worker_data_empty() {
        let data = WorkerData::new();
        assert!(!data.is_loaded());
        assert!(data.is_empty());
        assert!(!data.has_any_workers());
    }

    #[test]
    fn test_worker_data_loading_message() {
        let data = WorkerData::new();
        let summary = data.format_worker_pool_summary();
        assert!(summary.contains("Loading"));
    }

    #[test]
    fn test_format_status() {
        assert_eq!(format_status(&WorkerStatus::Active), "Active");
        assert_eq!(format_status(&WorkerStatus::Idle), "Idle");
        assert_eq!(format_status(&WorkerStatus::Failed), "Failed");
    }

    #[test]
    fn test_worker_data_with_tmux() {
        let mut data = WorkerData::new();
        data.last_update = Some(std::time::Instant::now());

        // Initially empty
        assert!(!data.has_any_workers());

        // Add tmux sessions
        let discovery = DiscoveryResult {
            workers: vec![],
            by_type: std::collections::HashMap::new(),
            attached_count: 0,
            detached_count: 0,
        };
        data.update_from_tmux(discovery);

        // Still no workers
        assert!(!data.has_any_workers());
        assert_eq!(data.total_worker_count(), 0);
    }

    // ============================================================
    // Initialization Performance Tests
    // ============================================================
    //
    // These tests verify that DataManager initialization is fast enough
    // to meet the < 2 second startup target. Each component should
    // initialize within 500ms.

    /// Test that DataManager initialization completes within 2 seconds.
    /// This is the primary performance validation for fg-2ir.
    #[test]
    fn test_datamanager_init_under_2_seconds() {
        use std::time::{Duration, Instant};

        let start = Instant::now();
        let _manager = DataManager::new();
        let elapsed = start.elapsed();

        // DataManager::new() should complete in under 2 seconds
        assert!(
            elapsed < Duration::from_secs(2),
            "DataManager::new() took {:?}, exceeds 2 second target",
            elapsed
        );

        // In practice, it should be much faster (< 10ms typically)
        // This is a sanity check, not a strict requirement
        if elapsed > Duration::from_millis(100) {
            eprintln!(
                "Warning: DataManager::new() took {:?}, consider optimization",
                elapsed
            );
        }
    }

    /// Test initialization with a temporary empty status directory.
    /// This simulates a fresh installation with no workers.
    #[test]
    fn test_datamanager_init_empty_status_dir() {
        use std::time::{Duration, Instant};
        use tempfile::TempDir;

        let temp_dir = TempDir::new().unwrap();
        let status_dir = temp_dir.path().join("status");
        std::fs::create_dir_all(&status_dir).unwrap();

        let start = Instant::now();
        let manager = DataManager::with_status_dir(status_dir);
        let elapsed = start.elapsed();

        assert!(
            elapsed < Duration::from_secs(2),
            "DataManager with empty status dir took {:?}",
            elapsed
        );

        // Verify manager works correctly (initial state has no workers from status files)
        // Note: worker_counts() returns 0 before first poll, which is correct for fast init
        assert_eq!(manager.worker_counts().total, 0);
    }

    /// Test initialization with 100 status files to verify O(n) scaling.
    /// This tests the scenario described in fg-2ir where users may have
    /// many workers running.
    #[test]
    fn test_datamanager_init_100_status_files() {
        use crate::status::{StatusWatcher, StatusWatcherConfig};
        use std::time::{Duration, Instant};
        use tempfile::TempDir;

        let temp_dir = TempDir::new().unwrap();
        let status_dir = temp_dir.path().join("status");
        std::fs::create_dir_all(&status_dir).unwrap();

        // Create 100 status files
        for i in 0..100 {
            let content = format!(
                r#"{{"worker_id": "worker-{}", "status": "active", "model": "test-model"}}"#,
                i
            );
            std::fs::write(status_dir.join(format!("worker-{}.json", i)), content).unwrap();
        }

        // Test StatusWatcher directly (which is responsible for loading status files)
        let config = StatusWatcherConfig::default().with_status_dir(&status_dir);

        let start = Instant::now();
        let watcher = StatusWatcher::new(config).unwrap();
        let elapsed = start.elapsed();

        // Even with 100 files, should complete well under 500ms
        assert!(
            elapsed < Duration::from_millis(500),
            "StatusWatcher with 100 status files took {:?}",
            elapsed
        );

        // Verify all workers were loaded during initial scan
        assert_eq!(
            watcher.workers().len(),
            100,
            "Should have loaded all 100 workers"
        );
    }

    /// Test that StatusWatcher initialization is fast (< 100ms target).
    #[test]
    fn test_statuswatcher_init_performance() {
        use crate::status::{StatusWatcher, StatusWatcherConfig};
        use std::time::{Duration, Instant};
        use tempfile::TempDir;

        let temp_dir = TempDir::new().unwrap();
        let status_dir = temp_dir.path().join("status");
        std::fs::create_dir_all(&status_dir).unwrap();

        let config = StatusWatcherConfig::default().with_status_dir(&status_dir);

        let start = Instant::now();
        let _watcher = StatusWatcher::new(config).unwrap();
        let elapsed = start.elapsed();

        assert!(
            elapsed < Duration::from_millis(100),
            "StatusWatcher init took {:?}, exceeds 100ms target",
            elapsed
        );
    }

    /// Test that BeadManager initialization is fast (< 50ms target).
    #[test]
    fn test_beadmanager_init_performance() {
        use crate::bead::BeadManager;
        use std::time::{Duration, Instant};

        let start = Instant::now();
        let mut manager = BeadManager::new();
        manager.add_default_workspaces();
        let elapsed = start.elapsed();

        assert!(
            elapsed < Duration::from_millis(50),
            "BeadManager init took {:?}, exceeds 50ms target",
            elapsed
        );
    }
}

