        data.total_decisions = 100;
        data.by_tier.insert(WorkerTier::Premium, 30);
        data.by_tier.insert(WorkerTier::Standard, 40);
        data.by_tier.insert(WorkerTier::Budget, 30);

        data.calculate_savings();

        // Should have some savings
